namespace sv_df78cff1448142b4bc450c50a111f395.Services;

public enum Severity { Info, Warning, Critical }

public sealed class NotificationItem
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

/// <summary>
/// Scoped per circuit. Holds notification state and raises <see cref="OnChange"/>
/// whenever that state is mutated so every subscribed component can re-render.
/// </summary>
public sealed class NotificationHub
{
    private readonly List<NotificationItem> _notifications = [];
    private readonly object _lock = new();

    /// <summary>
    /// Subscribers attach async callbacks. Each callback receives the hub instance
    /// so the subscriber can query current state.  The hub itself never touches
    /// the UI thread — callers are responsible for marshalling via
    /// <c>InvokeAsync</c>.
    /// </summary>
    public event Func<Task>? OnChange;

    public IReadOnlyList<NotificationItem> GetAll()
    {
        lock (_lock) return _notifications.ToList();
    }

    public int GetUnreadCount()
    {
        lock (_lock) return _notifications.Count(n => !n.IsRead);
    }

    public async Task AddNotificationAsync(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new NotificationItem
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        await NotifyAsync();
    }

    public async Task MarkAsReadAsync(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null) item.IsRead = true;
        }
        await NotifyAsync();
    }

    public async Task MarkAllReadAsync()
    {
        lock (_lock)
        {
            foreach (var n in _notifications) n.IsRead = true;
        }
        await NotifyAsync();
    }

    public async Task DismissNotificationAsync(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        if (OnChange is not null)
        {
            // Invoke every subscriber. Each subscriber is expected to marshal
            // onto its own synchronization context (ComponentBase.InvokeAsync).
            foreach (var handler in OnChange.GetInvocationList().Cast<Func<Task>>())
            {
                await handler();
            }
        }
    }
}

namespace sv_df78cff1448142b4bc450c50a111f395.Services;

/// <summary>
/// Scoped service that pushes a random notification every 15 seconds.
/// Started/stopped explicitly by the Dashboard page so it only runs
/// while that page is active.
/// </summary>
public sealed class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk space low",       "Server disk usage exceeded 90%.",         Severity.Critical),
        ("New deployment",       "v2.4.1 deployed to production.",          Severity.Info),
        ("CPU spike",            "CPU usage above 85% for 5 minutes.",      Severity.Warning),
        ("Backup completed",     "Nightly backup finished successfully.",   Severity.Info),
        ("Memory pressure",      "Available memory dropped below 512 MB.",  Severity.Warning),
        ("SSL cert expiring",    "Certificate expires in 7 days.",          Severity.Critical),
        ("Health check passed",  "All endpoints returned 200 OK.",          Severity.Info),
        ("Latency alert",        "P99 latency exceeded 500 ms.",            Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub) => _hub = hub;

    public void Start()
    {
        if (_timer is not null) return;
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _ = RunAsync(_cts.Token);
    }

    private async Task RunAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                var template = Templates[Random.Shared.Next(Templates.Length)];
                await _hub.AddNotificationAsync(template.Title, template.Message, template.Severity);
            }
        }
        catch (OperationCanceledException) { }
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose() => Stop();
}

