</a>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += OnHubChanged;
    }

    private async Task OnHubChanged()
    {
        _unreadCount = Hub.GetUnreadCount();
        // Marshal onto the renderer's sync context so StateHasChanged is safe
        // even when the notification originated from a background thread.
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

