@using sv_df78cff1448142b4bc450c50a111f395.Services
@implements IDisposable
@inject NotificationHub Hub

<PageTitle>Notifications</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Notifications</h1>
    @if (_notifications.Any(n => !n.IsRead))
    {
        <button class="btn btn-outline-primary" @onclick="MarkAllRead">Mark All Read</button>
    }
</div>

@if (!_notifications.Any())
{
    <p class="text-muted">No notifications yet.</p>
}
else
{
    @foreach (var group in _notifications
        .GroupBy(n => n.Severity)
        .OrderBy(g => g.Key switch { Severity.Critical => 0, Severity.Warning => 1, _ => 2 }))
    {
        <h4 class="mt-4">
            <span class="badge @BadgeClass(group.Key)">@group.Key</span>
        </h4>

        <ul class="list-group mb-3">
            @foreach (var n in group.OrderByDescending(x => x.Timestamp))
            {
                <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-light fw-bold")">
                    <div class="me-auto">
                        <div>@n.Title</div>
                        <small class="text-muted">@n.Message — @n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm ms-2">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => MarkRead(n.Id)">Mark Read</button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Dismiss(n.Id)">Dismiss</button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IReadOnlyList<NotificationItem> _notifications = [];

    protected override void OnInitialized()
    {
        _notifications = Hub.GetAll();
        Hub.OnChange += OnHubChanged;
    }

    private async Task OnHubChanged()
    {
        _notifications = Hub.GetAll();
        await InvokeAsync(StateHasChanged);
    }

    private async Task MarkRead(Guid id) => await Hub.MarkAsReadAsync(id);
    private async Task MarkAllRead()     => await Hub.MarkAllReadAsync();
    private async Task Dismiss(Guid id)  => await Hub.DismissNotificationAsync(id);

    private static string BadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}
"}

