@@ -1,0 +1,60 @@
+namespace sv_df78cff1448142b4bc450c50a111f395.Services;
+
+/// <summary>
+/// Scoped service that pushes a random notification every 15 seconds.
+/// Started/stopped explicitly by the Dashboard page so it only runs
+/// while that page is active.
+/// </summary>
+public sealed class SimulatorService : IDisposable
+{
+    private readonly NotificationHub _hub;
+    private PeriodicTimer? _timer;
+    private CancellationTokenSource? _cts;
+
+    private static readonly (string Title, string Message, Severity Severity)[] Templates =
+    [
+        ("Disk space low",       "Server disk usage exceeded 90%.",         Severity.Critical),
+        ("New deployment",       "v2.4.1 deployed to production.",          Severity.Info),
+        ("CPU spike",            "CPU usage above 85% for 5 minutes.",      Severity.Warning),
+        ("Backup completed",     "Nightly backup finished successfully.",   Severity.Info),
+        ("Memory pressure",      "Available memory dropped below 512 MB.",  Severity.Warning),
+        ("SSL cert expiring",    "Certificate expires in 7 days.",          Severity.Critical),
+        ("Health check passed",  "All endpoints returned 200 OK.",          Severity.Info),
+        ("Latency alert",        "P99 latency exceeded 500 ms.",            Severity.Warning),
+    ];
+
+    public SimulatorService(NotificationHub hub) => _hub = hub;
+
+    public void Start()
+    {
+        if (_timer is not null) return;
+        _cts = new CancellationTokenSource();
+        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
+        _ = RunAsync(_cts.Token);
+    }
+
+    private async Task RunAsync(CancellationToken ct)
+    {
+        try
+        {
+            while (await _timer!.WaitForNextTickAsync(ct))
+            {
+                var template = Templates[Random.Shared.Next(Templates.Length)];
+                await _hub.AddNotificationAsync(template.Title, template.Message, template.Severity);
+            }
+        }
+        catch (OperationCanceledException) { }
+    }
+
+    public void Stop()
+    {
+        _cts?.Cancel();
+        _timer?.Dispose();
+        _timer = null;
+        _cts?.Dispose();
+        _cts = null;
+    }
+
+    public void Dispose() => Stop();
+}
+

