@using sv_df78cff1448142b4bc450c50a111f395.Services
@implements IDisposable
@inject NotificationHub Hub

<div class="card">
    <div class="card-header">
        <strong>Recent Unread Notifications</strong>
    </div>
    <ul class="list-group list-group-flush">
        @if (!_recent.Any())
        {
            <li class="list-group-item text-muted">All caught up!</li>
        }
        else
        {
            @foreach (var n in _recent)
            {
                <li class="list-group-item d-flex justify-content-between align-items-start">
                    <div class="me-auto">
                        <span class="badge @BadgeClass(n.Severity) me-1">@n.Severity</span>
                        @n.Title
                        <br />
                        <small class="text-muted">@n.Message</small>
                    </div>
                    <button class="btn btn-sm btn-outline-danger ms-2" @onclick="() => Dismiss(n.Id)">
                        Dismiss
                    </button>
                </li>
            }
        }
    </ul>
</div>

@code {
    private IReadOnlyList<NotificationItem> _recent = [];

    protected override void OnInitialized()
    {
        RefreshRecent();
        Hub.OnChange += OnHubChanged;
    }

    private async Task OnHubChanged()
    {
        RefreshRecent();
        await InvokeAsync(StateHasChanged);
    }

    private void RefreshRecent()
    {
        _recent = Hub.GetAll()
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private async Task Dismiss(Guid id) => await Hub.DismissNotificationAsync(id);

    private static string BadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

